from pathlib import Path
import json
from typing import Dict, Any

def _cm_success(action, message, data=None):
    if message is None or message == '':
        message = str(action) + ' completed'
    return {'ok': True, 'action': str(action), 'message': str(message), 'data': data, 'error': None}

def _cm_failure(action, message, error, data=None):
    if message is None or message == '':
        message = str(action) + ' failed'
    if error is None or error == '':
        error = message
    return {'ok': False, 'action': str(action), 'message': str(message), 'data': data, 'error': str(error)}
SKILL_ROOT = Path(__file__).resolve().parent
DATA_DIR = SKILL_ROOT / 'data'
DATA_DIR.mkdir(parents=True, exist_ok=True)
DATA_DIR.mkdir(parents=True, exist_ok=True)

def add_task(name: str):
    if name is None or (isinstance(name, str) and (not name.strip())):
        return _cm_failure('add_task', 'name is required', 'missing_name', None)
    filename = f'{name}.json'
    path = DATA_DIR / filename
    try:
        with open(path, 'w', encoding='utf-8') as handle:
            json.dump({'name': name}, handle)
    except Exception as e:
        return _cm_failure('add_task', f'Failed to write file {filename}: {str(e)}', None, {'key': name})
    return _cm_success('add_task', 'Successfully added new task', {'name': name})

def get_tasks():
    tasks = []
    for path in DATA_DIR.glob('*.json'):
        with open(path, 'r', encoding='utf-8') as handle:
            data = json.load(handle)
            tasks.append({'name': data['name'], 'filename': str(path)})
    return _cm_success('get_tasks', 'Successfully retrieved tasks', {'tasks': tasks})

def delete_task(name: str):
    if name is None or (isinstance(name, str) and (not name.strip())):
        return _cm_failure('delete_task', 'name is required', 'missing_name', None)
    filename = f'{name}.json'
    path = DATA_DIR / filename
    try:
        path.unlink(missing_ok=True)
    except Exception as e:
        return _cm_failure('delete_task', f'Failed to delete file {filename}: {str(e)}', None, {'name': name})
    return _cm_success('delete_task', 'Successfully removed task', {'name': name})

def schema():
    return {'package': 'simple_todo', 'endpoints': {'add_task': {'args': ['name'], 'returns': 'dict'}, 'get_tasks': {'args': [], 'returns': 'dict'}, 'delete_task': {'args': ['name'], 'returns': 'dict'}}, 'response_format': 'ok, action, message, data, error', 'storage_notes': f'Persistent files must live under {DATA_DIR} using Path operations.', 'notes': ''}

